const body = $input.first().json.body || $input.first().json;

// ── File source check ────────────────────────────────────────
if (!body.fileUrl && !body.filename) {
  throw new Error('Provide either fileUrl (remote document) or filename (for binary upload).');
}

// ── Filename & extension allowlist ───────────────────────────
const filename = body.filename ||
  body.fileUrl?.split('?')[0].split('/').pop() ||
  'invoice.pdf';
const ext = filename.split('.').pop()?.toLowerCase() || 'pdf';
const allowedExts = ['pdf', 'jpg', 'jpeg', 'png', 'tiff'];
if (!allowedExts.includes(ext)) {
  throw new Error(`File type .${ext} not allowed. Accepted: ${allowedExts.join(', ')}`);
}

// ── MIME type map ─────────────────────────────────────────────
const mimeMap = {
  pdf: 'application/pdf',
  jpg: 'image/jpeg', jpeg: 'image/jpeg',
  png: 'image/png',
  tiff: 'image/tiff'
};
const mimeType = mimeMap[ext] || 'application/octet-stream';

// ── Structured filename ───────────────────────────────────────
const ts = new Date().toISOString().split('T')[0];
const structuredFilename = `invoice_${ts}_${filename.replace(/[^a-zA-Z0-9._-]/g, '_')}`;

// ── Sanitise metadata ─────────────────────────────────────────
const sanitise = s => String(s || '').trim().slice(0, 255);

return [{
  json: {
    fileUrl: body.fileUrl || null,
    filename,
    structuredFilename,
    mimeType,
    ext,
    uploadedBy: sanitise(body.uploadedBy) || 'Unknown',
    department: sanitise(body.department) || 'General',
    notes: sanitise(body.notes),
    receivedAt: new Date().toISOString()
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate Payload').first().json;

const cdnUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!cdnUrl) {
  throw new Error('Upload to URL returned no public URL. Raw: ' + JSON.stringify(uploadResp).slice(0, 300));
}

return [{
  json: {
    ...meta,
    cdnUrl: cdnUrl.replace(/^http:\/\//, 'https://'),
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

const textractResp = $input.first().json;
const meta = $('Extract CDN URL').first().json;

// ── Helper: pull value from Textract ExpenseFields ────────────
const getField = (fields, ...labels) => {
  for (const label of labels) {
    const match = fields?.find(
      f => f.Type?.Text?.toUpperCase() === label.toUpperCase()
    );
    if (match?.ValueDetection?.Text) return match.ValueDetection.Text.trim();
  }
  return null;
};

// ── Extract summary fields from Textract response ─────────────
const summaryFields =
  textractResp.ExpenseDocuments?.[0]?.SummaryFields || [];

const rawVendor    = getField(summaryFields, 'VENDOR_NAME', 'NAME', 'SUPPLIER_NAME');
const rawInvoiceNo = getField(summaryFields, 'INVOICE_RECEIPT_ID', 'INVOICE_NUMBER', 'RECEIPT_ID', 'PO_NUMBER');
const rawAmount    = getField(summaryFields, 'AMOUNT_DUE', 'TOTAL', 'AMOUNT', 'GRAND_TOTAL', 'INVOICE_TOTAL');
const rawDueDate   = getField(summaryFields, 'DUE_DATE', 'PAYMENT_DUE_DATE', 'PAY_BY');
const rawCurrency  = getField(summaryFields, 'CURRENCY') || 'USD';
const rawIssueDate = getField(summaryFields, 'INVOICE_RECEIPT_DATE', 'DATE', 'ISSUE_DATE');

// ── Normalise amount ──────────────────────────────────────────
const parseAmount = raw => {
  if (!raw) return null;
  const cleaned = raw.replace(/[^0-9.,-]/g, '').replace(',', '');
  const val = parseFloat(cleaned);
  return isNaN(val) ? null : val;
};

// ── Normalise date to YYYY-MM-DD ──────────────────────────────
const parseDate = raw => {
  if (!raw) return null;
  try {
    const d = new Date(raw);
    if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];
  } catch {}
  return raw; // return raw if unparseable
};

const vendor    = rawVendor || 'Unknown Vendor';
const invoiceNo = rawInvoiceNo || `AUTO-${Date.now()}`;
const amount    = parseAmount(rawAmount);
const dueDate   = parseDate(rawDueDate);
const issueDate = parseDate(rawIssueDate);
const currency  = rawCurrency.toUpperCase().slice(0, 3);

// ── Determine completeness ────────────────────────────────────
const missingFields = [];
if (!rawVendor)    missingFields.push('vendor');
if (!rawInvoiceNo) missingFields.push('invoice_number');
if (amount === null) missingFields.push('amount');
if (!dueDate)      missingFields.push('due_date');

const extractionStatus = missingFields.length === 0 ? 'complete' : 'incomplete';

// ── Extract line items (first 10) ────────────────────────────
const lineItemGroups =
  textractResp.ExpenseDocuments?.[0]?.LineItemGroups || [];
const lineItems = lineItemGroups
  .flatMap(g => g.LineItems || [])
  .slice(0, 10)
  .map(item => {
    const fields = item.LineItemExpenseFields || [];
    return {
      description: getField(fields, 'ITEM', 'PRODUCT_CODE', 'EXPENSE_ROW') || '',
      quantity: getField(fields, 'QUANTITY') || '',
      unitPrice: getField(fields, 'UNIT_PRICE', 'PRICE') || '',
      total: getField(fields, 'AMOUNT') || ''
    };
  });

return [{
  json: {
    ...meta,
    // Extracted fields
    vendor,
    invoiceNo,
    amount,
    currency,
    dueDate,
    issueDate,
    lineItems,
    // Status
    extractionStatus,
    missingFields,
    invoiceStatus: 'pending',
    // Raw for audit
    textractConfidence: textractResp.ExpenseDocuments?.[0]?.SummaryFields?.length || 0
  }
}];

const searchResult = $input.first().json;
const invoiceData = $('Parse & Validate Extracted Data').first().json;

// Sheets returns an array of matching rows
const existingRows = Array.isArray(searchResult) ? searchResult : (searchResult.values || []);
const existingRow = existingRows.length > 0 ? existingRows[0] : null;

let writeAction = 'append'; // default
let isDuplicate = false;

if (existingRow) {
  const existingStatus = existingRow['Status'] || existingRow.status || '';
  if (existingStatus.toLowerCase() === 'incomplete' && invoiceData.extractionStatus === 'complete') {
    // Allow update: previous extraction was partial, this one is complete
    writeAction = 'update';
  } else {
    // True duplicate — skip write
    writeAction = 'skip';
    isDuplicate = true;
  }
}

return [{
  json: {
    ...invoiceData,
    writeAction,
    isDuplicate,
    existingRowId: existingRow?.row_number || existingRow?.id || null
  }
}];

// Duplicate — skip Sheets write, pass through for Slack + response
const data = $input.first().json;
return [{
  json: {
    ...data,
    invoiceStatus: 'duplicate',
    sheetsRowId: data.existingRowId,
    skippedWrite: true
  }
}];

// Normalise response from all three Sheets branches
const sheetsResp = $input.first().json;
const invoiceData = $('Resolve Write Action').first().json;

const sheetsRowId =
  sheetsResp.updatedRange ||
  sheetsResp.updates?.updatedRange ||
  invoiceData.sheetsRowId ||
  null;

return [{
  json: {
    ...invoiceData,
    sheetsRowId,
    sheetsWritten: !invoiceData.skippedWrite
  }
}];

